import React from "react";

// Exemplo: Você pode colocar os ícones SVG diretamente ou importar de uma lib de ícones.
export default function Header() {
  return (
    <header className="fixed top-0 left-0 right-0 z-50 flex items-center justify-between h-16 px-6 bg-white shadow-sm">
      {/* Logo e nome */}
      <div className="flex items-center gap-3">
        <span className="w-10 h-10 flex items-center justify-center rounded-full bg-indigo-100">
          {/* Ícone asterisco ou logotipo SVG */}
          <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="currentColor" class="size-6">
  <path fill-rule="evenodd" d="M1.5 7.125c0-1.036.84-1.875 1.875-1.875h6c1.036 0 1.875.84 1.875 1.875v3.75c0 1.036-.84 1.875-1.875 1.875h-6A1.875 1.875 0 0 1 1.5 10.875v-3.75Zm12 1.5c0-1.036.84-1.875 1.875-1.875h5.25c1.035 0 1.875.84 1.875 1.875v8.25c0 1.035-.84 1.875-1.875 1.875h-5.25a1.875 1.875 0 0 1-1.875-1.875v-8.25ZM3 16.125c0-1.036.84-1.875 1.875-1.875h5.25c1.036 0 1.875.84 1.875 1.875v2.25c0 1.035-.84 1.875-1.875 1.875h-5.25A1.875 1.875 0 0 1 3 18.375v-2.25Z" clip-rule="evenodd" />
</svg>



        </span>
        <span className="font-bold text-lg text-[#0D0F1C]">PoliUB Atendimento</span>
      </div>

      {/* Espaço em branco para grow */}
      <div className="flex-1"></div>

      {/* Ícones à direita */}
      <div className="flex items-center gap-6">
        {/* Sininho de notificações */}
        <span className="w-10 h-10 flex items-center justify-center rounded-full bg-indigo-100">
          {/* Substitua pelo SVG do sino */}
          <svg width="20" height="20" fill="none" stroke="#1E293B" strokeWidth="2" viewBox="0 0 24 24">
            <path d="M15 17h5l-1.405-1.405A2.032 2.032 0 0 1 18 14.158V11a6.002 6.002 0 0 0-5-5.917V4a2 2 0 1 0-4 0v1.083A6.002 6.002 0 0 0 4 11v3.159c0 .538-.214 1.055-.595 1.436L2 17h5m8 0v1a3 3 0 0 1-6 0v-1m6 0H9" />
          </svg>
        </span>
        {/* Avatar */}
        <span className="w-10 h-10 flex items-center justify-center rounded-full bg-[#F5D4CC] overflow-hidden">
          <img
            src="https://randomuser.me/api/portraits/women/68.jpg"
            alt="avatar"
            className="w-8 h-8 object-cover rounded-full"
          />
        </span>
      </div>
    </header>
  );
}
